insert into core.role_permissions(role_id,permission_id) select r.id,p.id from core.roles r join core.permissions p on p.code=any(array['system.crm.access', 'crm.dashboard.view', 'crm.database.view', 'crm.customer.view', 'crm.customer.update', 'crm.customer.change_status', 'crm.customer.add_note', 'crm.inbox.view', 'crm.conversation.view', 'crm.conversation.send_text', 'crm.conversation.send_template', 'crm.conversation.send_media', 'crm.conversation.download_attachment', 'crm.conversation.mark_read']::text[]) where r.code='customer_service_agent' on conflict do nothing;
insert into core.role_permissions(role_id,permission_id) select r.id,p.id from core.roles r join core.permissions p on p.code=any(array['system.tracking.access', 'tracking.orders.view', 'tracking.order.open', 'tracking.link.create', 'tracking.link.copy']::text[]) where r.code='tracking_user' on conflict do nothing;
